import React, { useEffect, useState } from 'react';
// import Link from 'next/link';
import { Accordion, Button, Card, Col, Form, Row } from 'react-bootstrap';
import AccordionIcon from '../../components/AccordionIcon';
// import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
// import { faExternalLinkAlt } from '@fortawesome/free-solid-svg-icons';
// import { Duration } from 'luxon';
import * as Sentry from '@sentry/node';
import { useFranchiseeContext } from '../../context/Franchisee';
import { SET_PACKAGE, useLeadContext } from '../../context/Lead';
import Section from '../Section';
// import setLeadPrice from '../../SDKs/Gataware/partial/setLeadPrice';
import axios, { AxiosResponse } from 'axios';
import { useDispatch, useSelector } from 'react-redux';
import billingInfo, {
  BillingInfoData,
} from '../../SDKs/Gataware/partial/billingInfo';
import { HomeInfoData } from '../../SDKs/Gataware/partial/homeInfo';
import db from '../../SDKs/firebase/firebase';
import cleaningPackages, {
  CleaningPackageData,
} from '../../data/cleaningPackages';
import servicesJson from '../../data/services/services.json';
import {
  setDiscountPriceItemID,
  setSelectedPackageInStore,
  setSelectedPackageType,
  setServiceFee,
  setTaxID,
} from '../../features/user/userSlice';
// import ServiceModal from '../ServiceModal';
import { useDebouncedCallback } from 'use-debounce';

type PackageType = null | 'single' | 'weekly' | 'biweekly' | 'monthly';

interface BookingPackageSelectionProps {
  packageDisabled?: boolean;
  isReturningCustomer?: boolean;
}

interface RoomObject {
  id: string;
  label: string;
  list: Array<string>;
}
interface PackageObject {
  id: string;
  label: string;
  description: string;
  rooms: Array<RoomObject>;
}

const BookingPackageSelection: React.FC<BookingPackageSelectionProps> = ({
  packageDisabled,
  isReturningCustomer
}: BookingPackageSelectionProps) => {
  // const franchiseeId = useFranchiseeContext()?.franchisee?.id;
  const { lead, dispatchLead } = useLeadContext();
  const { bedrooms, bathrooms, people, pets, squareFootage } = lead;

  const [disabled, setDisabled] = useState<boolean>(true);
  const [showModal, setShowModal] = useState<boolean>(false);
  const dispatch = useDispatch();
  let onlineUserReference;

  function toggleModal() {
    setShowModal(!showModal);
  }

  const [packageType, setPackageType] = useState<string>(null);
  const [packages, setPackages] = useState<Array<CleaningPackageData>>([]);
  const [selectedPackage, setSelectedPackage] = useState<number | null>(null);
  const [description, setDescription] = useState<string | null>(null);
  const [servicesSlug, setServicesSlug] = useState<string>('');
  const [servicesName, setServicesName] = useState<string>('');
  const [activePackage, setActivePackage] = useState<PackageObject>(null);
  const [activeSlug, setActiveSlug] = useState<string>('');
  const [packageTypeName, setPackageTypeName] = useState<string>('');

  const { franchisee } = useFranchiseeContext();

  useEffect(() => {
    if (packageType) {
      setPackages(cleaningPackages[packageType]);
    } else {
      setPackages([]);
      setSelectedPackage(null);
    }
  }, [packageType]);

  const detectUserAction = () => {
    if (lead?.id === -1) return;
    try {
      onlineUserReference = db.ref(`/online/${lead?.id}`);
      onlineUserReference.update({ typing: true });

      setTimeout(() => {
        onlineUserReference.update({ typing: false });
      }, 500);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {

    if (lead?.squareFootage && lead?.id) {
      setDisabled(false);
    } else {
      setDisabled(true);
    }

    if (lead.package === null) return;
    Object.entries(cleaningPackages).forEach((cleaningPackage) => {
      const packageName = cleaningPackage[0];
      for (let packages of cleaningPackage[1]) {
        if (packages.id === lead.package) {
          setPackageType(packageName);
          setSelectedPackage(packages.id);
          setPackages(cleaningPackages[packageName]);
        }
      }
    });
  }, [lead]);

  useEffect(() => {
    setSelectedPackage(null)
  }, [isReturningCustomer])

  useEffect(() => {
    setLeadPrice.callback();
  }, [bedrooms, bathrooms, people, pets, squareFootage, selectedPackage]);

  const setLeadPrice = useDebouncedCallback(
    () => {
      if (selectedPackage) {
        const [selected] = packages.filter(({ id }) => id === selectedPackage);
        
        // console.log(`The first selected is: ${JSON.stringify(selected)}`);
        if (selected === undefined) return;
        axios
          .post('/api/set-lead-price/', {
            leadId: lead.id,
            packageId: selected.id,
          })
          .then(({ data, status }: AxiosResponse) => {
  
            dispatchLead({
              type: SET_PACKAGE,
              payload: data.lead,
            });
  
            try {
              db.ref(
                process.env.kpiDashboardCollectionName + '/' + data?.lead?.id
              ).update({
                packageId: selected.id,
                step: 3,
              });
            } catch (error) {
              console.log(error);
              Sentry.captureException(error);
            }
  
            try {
              const userStatusDatabaseRef = db.ref(`/online/${lead?.id}`);
  
              db.ref('.info/connected').on('value', async (snap) => {
                if (snap.val() === true) {
                  await userStatusDatabaseRef.onDisconnect().remove();
                  await userStatusDatabaseRef.set({
                    leadID: lead?.id,
                  });
                } else {
                  await userStatusDatabaseRef.remove();
                }
              });
            } catch (error) {
              console.log(error);
            }
          })
          .catch((error) => {
            // console.log('SetLeadPrice Error', { error });
            Sentry.captureException(error);
          });
        detectUserAction();
      }
    },
    1000,
    { trailing: true }
  );

  const hitAPI = async (fran) => {
    try {
      setShowModal(false);
      return;
      if (lead === null || lead?.id === -1 ) { return; }
      
      const requestData: BillingInfoData = {
        firstName: lead.firstName,
        lastName: lead.lastName,
        email: lead.email,
        phonePrimary: lead.phonePrimary,
        franchiseeId: fran.id !== -1 ? fran.id : lead?.franchisee,
        leadNotification: true,
        referral: lead.referral,
        zipCode: lead.zipCode
      };

      setShowModal(false);

      const requestTwo = await axios.post('/api/set-lead-price/', {
        leadId:lead.id,
        packageId: lead.package,
      });

      axios
        .all([requestTwo])
        .then(
          axios.spread((...responses) => {
            const responseOne = responses[0].data;
            const responseTwo = responses[1].data;

            dispatchLead({ type: 'HOME_INFO', payload: responseOne.lead });
            dispatchLead({
              type: 'SET_PACKAGE',
              payload: responseTwo.lead,
            });
          })
        )
        .catch((errors) => {
          console.error(errors);
        });
    } catch (err) {
      console.log(err);
      Sentry.captureException(err);
    }
  };

  useEffect(() => {
    if (lead.package !== null && lead.squareFootage > 0) {
      try {
        hitAPI(franchisee);
      } catch (err) {
        console.log(err);
        Sentry.captureException(err);
      }
    }
  }, [lead.email]);


  const [activeEventKey, setActiveEventKey] = useState('-1');
  function toggleEventKey(eventKey: string): void {
    if (activeEventKey === eventKey) {
      setActiveEventKey('-1');
    } else {
      setActiveEventKey(eventKey);
    }
  }

  return (
    <>
      {/* <Section padding='none' lg={8} className='justify-content-center booking-package-section'> */}
      <Form
        id='booking-form-package-info'
        className='needs-validation'
        noValidate
      >
        <div
          className={`booking-package-info book__gated ${
            !packageDisabled && 'active'
          } justify-content-center`}
        >
          <Form.Label className='form-section-header'>
            What Type of Cleaning Would You Like?
          </Form.Label>
          <Row className='' style={{ padding: 0 }}>
            <Col xs={6} md={3} className='my-4 text-left'>
              <Form.Check
                custom
                inline
                type='radio'
                id='bookRecurringFalse'
                name='packageType'
                data-value='single'
                data-calculated-field='true'
                disabled={packageDisabled}
                label={
                  <strong
                    className='text-primary form-section-labels'
                    id='one-time-button-label'
                  >
                    One-Time
                  </strong>
                }
                checked={packageType === 'single'}
                onClick={() => {
                  setPackageType('single');
                  dispatch(setSelectedPackageType('single'));
                }}
              />
            </Col>
            <Col xs={6} md={3} className='my-4 text-left'>
              <Form.Check
                custom
                inline
                type='radio'
                id='bookWeeklyTrue'
                name='packageType'
                value='weekly'
                data-value='weekly'
                data-calculated-field='true'
                disabled={packageDisabled}
                label={
                  <strong className='text-primary form-section-labels'>
                    Weekly
                  </strong>
                }
                checked={packageType === 'weekly'}
                onClick={() => {
                  setPackageType('weekly');
                  dispatch(setSelectedPackageType('weekly'));
                }}
              />
            </Col>
            <Col xs={6} md={3} className='my-4 text-left'>
              <Form.Check
                custom
                inline
                type='radio'
                id='bookBiweeklyTrue'
                name='packageType'
                value='biweekly'
                data-value='biweekly'
                data-calculated-field='true'
                disabled={packageDisabled}
                label={
                  <strong className='text-primary text-center text-md-left form-section-labels'>
                    Every 2 Weeks
                  </strong>
                }
                checked={packageType === 'biweekly'}
                onClick={() => {
                  setPackageType('biweekly');
                  dispatch(setSelectedPackageType('biweekly'));
                }}
              />
            </Col>
            <Col xs={6} md={3} className='my-4 text-left'>
              <Form.Check
                custom
                inline
                type='radio'
                id='bookMonthlyTrue'
                name='packageType'
                value='monthly'
                data-value='monthly'
                data-calculated-field='true'
                disabled={packageDisabled}
                label={
                  <strong className='text-primary form-section-labels'>
                    Every 4 Weeks
                  </strong>
                }
                checked={packageType === 'monthly'}
                onClick={() => {
                  setPackageType('monthly');
                  dispatch(setSelectedPackageType('monthly'));
                }}
              />
            </Col>
          </Row>

          <Form.Row className='text-lg-left'>
            <Form.Group as={Col} className='select__package-col'>
              {/* <Form.Label htmlFor='bookPackage' className='form-section-header'>
                  Select a Cleaning Package
                </Form.Label> */}
              <div className='book__select-buttons mb-3'>
                
                {packages.length > 0 &&
                  cleaningPackages[packageType] && (
                    <Form.Label
                      htmlFor='bookPackage'
                      className='form-section-header select-package-header'
                    >
                      Select a Cleaning Package
                    </Form.Label>
                  )}
                {packages.length > 0 &&
                  cleaningPackages[packageType]?.map(
                    ({ name, id, slug, description }: CleaningPackageData) => (
                      <Button
                        variant='outline-pink'
                        id={`package-${id}`}
                        data-type={packageType}
                        data-package={id}
                        data-calculated-field='true'
                        key={name}
                        className={id === selectedPackage && 'active'}
                        onClick={() => {
                          setSelectedPackage(id);
                          setActiveSlug(slug.split('/')[1]);
                          setPackageTypeName(name);
                          setDescription(description);
                          setServicesSlug(slug);
                          setServicesName(name);
                        }}
                      >
                        {name}
                      </Button>
                    )
                  )}
              </div>
            </Form.Group>
          </Form.Row>
        </div>
      </Form>
      {/* </Section> */}

      {description && (
        <>
          {servicesName.includes('Alternating') ? (
            <p>
              With the Alternating Cleaning Package we are able to alternate
              your cleaning services between our Premium and Touch-Up cleaning
              services. This specific cleaning package is best suited for the
              homeowner who does not require detailed cleaning on a regular
              basis, but still wishes to receive high quality house cleaning
              once a week, or every other week.
            </p>
          ) : (
            <>
              <p>{description}</p>

              {/* The number of hours that will be serviced with DWT package  */}
              {/* {selectedPackage === 1 && (
                <p>Based on the square footage of your home, you will recieve {lead.duration} hours of cleaning.</p>
              )} */}
            </>
          )}
          <hr />
        </>
      )}
    </>
  );
};

export default BookingPackageSelection;
